import{_ as e,o as s,c as o,ag as a}from"./chunks/framework.B3ZMliSr.js";const g=JSON.parse('{"title":"Format Reference","description":"Encoding details for all 7 supported MTProto session string formats.","frontmatter":{"title":"Format Reference","description":"Encoding details for all 7 supported MTProto session string formats."},"headers":[],"relativePath":"session-converter/formats.md","filePath":"session-converter/formats.md","lastUpdated":1783313024000}'),d={name:"session-converter/formats.md"};function i(r,t,n,l,c,h){return s(),o("div",null,[...t[0]||(t[0]=[a(`<h1 id="format-reference" tabindex="-1">Format Reference <a class="header-anchor" href="#format-reference" aria-label="Permalink to &quot;Format Reference&quot;">​</a></h1><p>Each MTProto library encodes session data differently. session-converter abstracts these into a common <a href="/website/session-converter/api#session"><code>Session</code></a> struct, so you can convert freely between formats.</p><h2 id="format-constants" tabindex="-1">Format constants <a class="header-anchor" href="#format-constants" aria-label="Permalink to &quot;Format constants&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Constant</th><th>Value</th></tr></thead><tbody><tr><td><code>FormatTelethon</code></td><td><code>&quot;telethon&quot;</code></td></tr><tr><td><code>FormatPyrogram</code></td><td><code>&quot;pyrogram&quot;</code></td></tr><tr><td><code>FormatGramJS</code></td><td><code>&quot;gramjs&quot;</code></td></tr><tr><td><code>FormatMtcute</code></td><td><code>&quot;mtcute&quot;</code></td></tr><tr><td><code>FormatMTKruto</code></td><td><code>&quot;mtkruto&quot;</code></td></tr><tr><td><code>FormatGogram</code></td><td><code>&quot;gogram&quot;</code></td></tr><tr><td><code>FormatGotgproto</code></td><td><code>&quot;gotgproto&quot;</code></td></tr></tbody></table><h2 id="encoding-details" tabindex="-1">Encoding details <a class="header-anchor" href="#encoding-details" aria-label="Permalink to &quot;Encoding details&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Fields</th><th>Encoding</th></tr></thead><tbody><tr><td><strong>Telethon</strong></td><td>dc, ip, port, [api_id], auth_key</td><td><code>&quot;1&quot;</code> prefix + base64url</td></tr><tr><td><strong>Pyrogram</strong></td><td>dc, api_id, test_mode, auth_key, user_id, is_bot</td><td>base64url (no prefix)</td></tr><tr><td><strong>GramJS</strong></td><td>dc, addr_len, addr, port, auth_key</td><td><code>&quot;1&quot;</code> prefix + base64std</td></tr><tr><td><strong>mtcute</strong></td><td>version, flags, dc_option (TL), user_id, is_bot, auth_key</td><td>base64url</td></tr><tr><td><strong>MTKruto</strong></td><td>dc_string, auth_key, api_id, is_bot, user_id</td><td>RLE + base64url</td></tr><tr><td><strong>gogram</strong></td><td>auth_key, hash, dc_id, ip_addr, app_id</td><td><code>&quot;1BvE&quot;</code> prefix + base64url(JSON)</td></tr><tr><td><strong>gotgproto</strong></td><td>dc, addr, auth_key, auth_key_id, salt, config</td><td>base64std(JSON)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Pyrogram has no server address</p><p>Pyrogram session strings do <strong>not</strong> include the server IP/port — only the DC ID. After decoding, session-converter fills the address and port from built-in DC defaults.</p></div><h2 id="auto-detection" tabindex="-1">Auto-detection <a class="header-anchor" href="#auto-detection" aria-label="Permalink to &quot;Auto-detection&quot;">​</a></h2><p><code>Decode()</code> and <code>DetectFormat()</code> identify the format without fully decoding. The detection priority is:</p><ol><li><strong>gogram</strong> — <code>&quot;1BvE&quot;</code> / <code>&quot;1BvX&quot;</code> prefix</li><li><strong>gotgproto</strong> — JSON structure</li><li><strong>Telethon / GramJS</strong> — <code>&quot;1&quot;</code> prefix, distinguishable by base64 variant (URL-safe vs standard) and address-length header</li><li><strong>Pyrogram</strong> — decoded payload length (271 / 351 / 356 bytes)</li><li><strong>mtcute</strong> — first byte is <code>3</code> (version)</li><li><strong>MTKruto</strong> — TL heuristic (last resort, most ambiguous)</li></ol><p>When detection is inconclusive, <code>Decode()</code> brute-forces all formats and returns the first that decodes successfully.</p><h2 id="sqlite-files" tabindex="-1">SQLite files <a class="header-anchor" href="#sqlite-files" aria-label="Permalink to &quot;SQLite files&quot;">​</a></h2><p>Telethon and Pyrogram can store sessions in SQLite <code>.session</code> files instead of strings. session-converter auto-detects which library produced the file by examining table names:</p><table tabindex="0"><thead><tr><th>Library</th><th>Table signature</th></tr></thead><tbody><tr><td>Telethon</td><td><code>sessions</code>, <code>entities</code>, <code>version</code></td></tr><tr><td>Pyrogram</td><td><code>sessions</code> (different schema)</td></tr></tbody></table><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">session, format, err </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tgconv.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ReadSQLite</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;myaccount.session&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// format == tgconv.SQLiteTelethon or tgconv.SQLitePyrogram</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Pure-Go SQLite</p><p><code>ReadSQLite</code> uses <code>modernc.org/sqlite</code> — no CGO, no system SQLite dependency. The file is opened read-only; the original session file is never modified.</p></div><h2 id="field-availability" tabindex="-1">Field availability <a class="header-anchor" href="#field-availability" aria-label="Permalink to &quot;Field availability&quot;">​</a></h2><p>Not every format populates every field. The auth key and DC ID are always present; the rest depend on the source:</p><table tabindex="0"><thead><tr><th>Field</th><th style="text-align:center;">Always present</th><th style="text-align:center;">Conditional</th></tr></thead><tbody><tr><td><code>AuthKey</code></td><td style="text-align:center;">✓</td><td style="text-align:center;"></td></tr><tr><td><code>DCID</code></td><td style="text-align:center;">✓</td><td style="text-align:center;"></td></tr><tr><td><code>ServerAddress</code></td><td style="text-align:center;"></td><td style="text-align:center;">Telethon, GramJS, mtcute, gotgproto</td></tr><tr><td><code>Port</code></td><td style="text-align:center;"></td><td style="text-align:center;">Telethon, GramJS, mtcute, gotgproto</td></tr><tr><td><code>AppID</code></td><td style="text-align:center;"></td><td style="text-align:center;">Pyrogram, mtcute, MTKruto, gogram</td></tr><tr><td><code>UserID</code></td><td style="text-align:center;"></td><td style="text-align:center;">Pyrogram, mtcute, MTKruto</td></tr><tr><td><code>IsBot</code></td><td style="text-align:center;"></td><td style="text-align:center;">Pyrogram, mtcute, MTKruto</td></tr><tr><td><code>TestMode</code></td><td style="text-align:center;"></td><td style="text-align:center;">Pyrogram</td></tr></tbody></table><p>When converting to a format that requires a field not present in the source, you can fill it manually before encoding:</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">session, _, _ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tgconv.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Decode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sessionString)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">session.AppID </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2040</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">session.UserID </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 123456789</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">session.IsBot </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">out, _ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tgconv.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Encode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(session, tgconv.FormatPyrogram)</span></span></code></pre></div>`,21)])])}const u=e(d,[["render",i]]);export{g as __pageData,u as default};
